/* 
   FRAMEWORK DEFINITIONSw
 */
var FRAMEWORKS = {
  RTF:{
    name:'RTF',
    promptBlock:function(t){
      return 'RTF FRAMEWORK ACTIVE:\n'
        +'• Display a learning objectives banner at the start of the simulation showing: "By the end of this simulation, students will be able to: [list 3 goals]"\n'
        +'• Each slider must have a tooltip label that connects it to prior curriculum knowledge (e.g. "This slider models the concept of [X] which you studied in [prior unit]")\n'
        +'• After EVERY round result, display a structured feedback box: "Your decision reflected: [concept] → This led to: [outcome] → This connects to: ['+t.concept+']"\n'
        +'• The feedback must be specific to the slider values chosen — not generic.'
    }
  },
  SPARK:{
    name:'SPARK',
    promptBlock:function(t){
      return 'SPARK FRAMEWORK ACTIVE:\n'
        +'• SPECIFIC: Each round must have a clearly stated specific focus question at the top (e.g. "Round 2: Focus on the relationship between [var A] and [resource B]")\n'
        +'• PURPOSEFUL: Display a "Why this matters" panel (2 sentences) before each round\n'
        +'• ADAPTIVE: If a student makes an incorrect prediction 2 rounds in a row, trigger a hint system: "Here\'s a hint to help your next prediction: [contextual clue]"\n'
        +'• RELEVANT: Each result must end with: "This connects to: '+t.real.split(',')[0]+'"\n'
        +'• KNOWLEDGE-BUILDING: At the start of rounds 2–5, show a "What you\'ve learned so far" summary recap card.'
    }
  },
  CREATE:{
    name:'CREATE',
    promptBlock:function(t){
      return 'CREATE FRAMEWORK ACTIVE:\n'
        +'• After round 3, unlock a "Design Your Own" mode where students can propose custom slider values outside the 0–4 range, with a text field to explain their creative reasoning\n'
        +'• Add an "Alternative Scenario" button at the end of each round: "What if you had made the opposite choice? Show the alternative outcome briefly."\n'
        +'• Final challenge at end of simulation: "You have seen the outcome. Now redesign one variable to prevent the worst outcome you observed. Justify your redesign."\n'
        +'• Exploratory mode: Allow free-play with no prediction required for one designated "exploration round" (label it clearly)'
    }
  },
  GRADE:{
    name:'GRADE',
    promptBlock:function(t){
      return 'GRADE FRAMEWORK ACTIVE:\n'
        +'• GOALS: Display the relevant IB Criterion for each round as a badge (e.g. "Criterion B: Investigating", "Criterion C: Communicating")\n'
        +'• RIGOR: Provide three difficulty tracks for each round:\n'
        +'  — Standard: Complete the prediction and read the outcome\n'
        +'  — Challenge: Write a 2-sentence cause-and-effect explanation before revealing\n'
        +'  — Extended HL: Answer a 4-mark examiner-style question before revealing\n'
        +'• AUDIENCE: Ensure all language is calibrated to '+t.atl+' level skills\n'
        +'• DIFFERENTIATION: The three difficulty tracks must be selectable by the student at the start\n'
        +'• EVIDENCE: Include an Evidence Log panel — a running record of all student decisions, predictions, and outcomes. Add a "Download Evidence as PDF/CSV" button at the end.'
    }
  },
  PERSONA:{
    name:'Persona Prompting',
    promptBlock:function(t,subj){
      var personas = {
        'Individuals & Societies':'You are also Dr. Amara Osei, a veteran development economist with 20 years advising the UN. Your advisor characters should speak with academic rigour and cite real examples from your field experience.',
        'Sciences':'You are also Dr. Priya Nair, a field ecologist who has spent 15 years studying the exact ecosystem this simulation models. Your advisor characters speak with scientific precision and mention specific species, pH values, and measurable thresholds.',
        'Economics':'You are also Professor James Kwak, a macroeconomist who has advised central banks. Your advisor characters reference real economic models (IS-LM, Phillips Curve) and historical parallels.',
        'Mathematics AA':'You are also Dr. Sofia Mendez, an applied mathematician who models real-world systems. Your advisor characters explain the mathematical elegance behind each outcome and connect to formal notation.',
        'Mathematics AI':'You are also Dr. Marcus Chen, a data scientist at a major firm. Your advisor characters interpret results in terms of statistical significance, confidence intervals, and real application.',
        'Computer Science':'You are also Dr. Anika Sharma, a researcher in AI ethics at a leading university. Your advisor characters frame outcomes in terms of real algorithmic systems and published research.',
        'Business Management':'You are also Dr. Rachel Foster, a business strategy consultant who has worked with Fortune 500 companies and IB HL students. Your advisor characters use real case studies and frameworks.',
        'Biology':'You are also Dr. Kenji Tanaka, a cell biologist whose lab studies exactly the biological process this simulation models. Your advisor characters use precise biological terminology.',
        'Chemistry':'You are also Dr. Fatima Al-Hassan, an industrial chemist with 15 years in process optimisation. Your advisor characters cite thermodynamic values, yield percentages, and industrial applications.',
        'Physics':'You are also Dr. Elena Kozlov, an experimental physicist who designs electromagnetic systems. Your advisor characters explain outcomes using precise equations and real engineering examples.',
        'ESS':'You are also Dr. Carlos Rivera, an IPCC contributing author and climate systems specialist. Your advisor characters cite IPCC reports, tipping point research, and real planetary boundaries.',
        'Global Politics':'You are also Prof. Ngozi Adeyemi, a political scientist who has worked with international development organisations. Your advisor characters reference real treaty frameworks, HDI data, and case studies.',
        'English A':'You are also Dr. Margaret Holt, a literary critic and IB English examiner. Your advisor characters model the analytical thinking expected in Paper 1 commentary — citing technique, effect, and purpose.',
        'Hindi A/B':'You are also Priyanka Sharma, a sociolinguist specialising in South Asian language acquisition. Your advisor characters reference research on Hindi-English bilingualism and Krashen\'s acquisition theory.',
        'Psychology':'You are also Dr. James Okafor, a cognitive psychologist and IB Psychology examiner. Your advisor characters frame all outcomes using formal psychological models (MSM, WMM) and cite key studies.',
        'PHE':'You are also Dr. Lucia Martinez, a sports scientist and Olympic performance consultant. Your advisor characters cite periodisation science, VO2 max research, and real athlete case studies.',
        'Arts':'You are also Dr. Yusuf Adebayo, a theatre director and arts management consultant. Your advisor characters frame decisions using real arts economics and critical theory.',
        'Design & Technology':'You are also Dr. Hana Kimura, a sustainable design engineer who has consulted for major electronics firms. Your advisor characters use lifecycle analysis terminology and cite specific product case studies.',
        'Mathematics':'You are also Dr. Paulo Freitas, a mathematician who applies number theory and statistics to real-world problems. Your advisor characters explain mathematical reasoning with precision and real-world examples.',
        'Language & Literature':'You are also Dr. Isabelle Moreau, a discourse analyst and IB Language A examiner. Your advisor characters model close reading, rhetorical analysis, and textual critique.',
        'Language Acquisition':'You are also Dr. Raj Kapoor, a Second Language Acquisition researcher. Your advisor characters reference Krashen\'s hypotheses, Vygotsky\'s ZPD, and real language learning research.',
        'Interdisciplinary (IH)':'You are also Dr. Sarah Okonkwo, an interdisciplinary researcher who combines environmental science and sociology. Your advisor characters explicitly bridge scientific and social science perspectives.'
      };
      var persona = personas[subj] || 'You are also an experienced IB educator and domain expert in this field. Your advisor characters speak with authority, cite real examples, and use discipline-appropriate language.';
      return 'PERSONA PROMPTING FRAMEWORK ACTIVE:\n'
        +persona+'\n'
        +'• All advisor character tooltips and result explanations must come through this expert persona — use first person where appropriate ("In my experience...", "The data shows...")\n'
        +'• Calibrate vocabulary and depth to IB '+t.atl+' skills level\n'
        +'• Include one "expert insight" callout per round that a non-expert would not know';
    }
  },
  COT:{
    name:'Chain of Thought',
    promptBlock:function(t){
      return 'CHAIN OF THOUGHT (CoT) FRAMEWORK ACTIVE:\n'
        +'• Before the Advance button activates, students must complete a Chain of Thought reasoning box with this exact structure:\n'
        +'  Step 1: "I am setting [variable] to [value] because..."\n'
        +'  Step 2: "I predict this will affect [resource] because..."\n'
        +'  Step 3: "The knock-on effect on [secondary resource] will be... because..."\n'
        +'  Step 4: "Therefore I predict the overall outcome will be: [prediction choice]"\n'
        +'• ALL four steps must be filled before Advance unlocks\n'
        +'• After the result is revealed, display: "Evaluating your chain: Step 1 was [accurate/inaccurate] because... Step 3 missed [X] because..."\n'
        +'• Highlight which step in the reasoning chain contained the logical gap, if any'
    }
  },
  TOT:{
    name:'Tree of Thought',
    promptBlock:function(t){
      return 'TREE OF THOUGHT (ToT) FRAMEWORK ACTIVE:\n'
        +'• After students set sliders and select a prediction — but BEFORE revealing the result — show a "Three Futures" card:\n'
        +'  Future A: [Brief description of an optimistic outcome — 2 sentences]\n'
        +'  Future B: [Brief description of the realistic/actual outcome — 2 sentences]\n'
        +'  Future C: [Brief description of a pessimistic outcome — 2 sentences]\n'
        +'• Students must rank Futures A, B, C by likelihood (drag-and-drop or radio buttons) and write ONE sentence justifying their #1 ranking\n'
        +'• THEN reveal the actual result — label it as Future [A/B/C]\n'
        +'• Display: "The actual outcome matched Future [X]. Here\'s why Future [Y] didn\'t happen: [explanation]"\n'
        +'• Discussion prompt at bottom: "What decision would have made Future A happen instead?"'
    }
  },
  REACT:{
    name:'ReAct',
    promptBlock:function(t){
      return 'ReAct FRAMEWORK ACTIVE — each round must have FOUR clearly labelled, sequential stages:\n'
        +'• REASON stage: Before touching any slider, students write their hypothesis: "My hypothesis for this round: If I [action], then [resource] will [change] because [reason]." This field is required.\n'
        +'• ACT stage: Students set sliders. Display: "You are now acting on your hypothesis."\n'
        +'• OBSERVE stage: After clicking Advance, the result appears WITH a structured reading guide: "Observe these three things: 1. [resource A] changed by... 2. [resource B] changed by... 3. The most surprising change was..."\n'
        +'• REFLECT stage: Required text field: "My mental model was [correct/partially correct/incorrect] because... Next round, I will adjust my thinking by..."\n'
        +'• The next round cannot begin until all REFLECT fields are completed\n'
        +'• Show RAOR progress indicator: Reason ✓ → Act ✓ → Observe ✓ → Reflect (pending)'
    }
  },
  SC:{
    name:'Self-Consistency',
    promptBlock:function(t){
      return 'SELF-CONSISTENCY (SC) FRAMEWORK ACTIVE:\n'
        +'• After the student selects their prediction — and BEFORE revealing the result — show "Expert Panel Predictions":\n'
        +'  Advisor 1 predicts: [prediction option] — "Because [1-sentence reasoning rooted in the key concept: '+t.concept+']"\n'
        +'  Advisor 2 predicts: [different prediction option] — "Because [1-sentence reasoning based on a different variable relationship]"\n'
        +'  Advisor 3 predicts: [same or different option] — "Because [1-sentence reasoning based on historical precedent]"\n'
        +'• Display: "You predicted [X]. Advisor 1 agrees / disagrees. Do you want to change your prediction? [Yes/Keep mine]"\n'
        +'• After the reveal: "Whose reasoning was most accurate? [Student/Advisor 1/2/3] — because [explanation]"\n'
        +'• Metacognitive prompt: "Did any advisor\'s reasoning change how you thought about this? Yes/No — explain in one sentence."\n'
        +'• Track across all rounds: "Your prediction accuracy vs Advisor Panel accuracy" — show comparison at end'
    }
  }
};

/* ══════════════════════════════════════════
   APPLICATION STATE & LOGIC
══════════════════════════════════════════ */
var state={prog:'MYP',subj:null,topic:null,style:'Bright, playful, cartoonish. Rounded characters, bold colours, friendly Google Font headings. Animated and fun.',frameworks:[],assessment:false,accessCode:''};

function switchTab(id,btn){
  document.querySelectorAll('.tab-content').forEach(function(el){el.classList.remove('active')});
  document.querySelectorAll('.tab-btn').forEach(function(el){el.classList.remove('active')});
  document.getElementById('tab-'+id).classList.add('active');
  btn.classList.add('active');
  window.scrollTo({top:0,behavior:'smooth'});
}

function setProg(p){
  state.prog=p;state.subj=null;state.topic=null;state.frameworks=[];
  document.getElementById('btn-myp').className='prog-btn'+(p==='MYP'?' a-myp':'');
  document.getElementById('btn-dp').className='prog-btn'+(p==='DP'?' a-dp':'');
  hide('topic-section');hide('enhancer-section');hide('custom-section');hide('out-section');
  filterGradeOptions(p);renderSubjects();
}

function filterGradeOptions(p){
  var sel=document.getElementById('f-grade');
  for(var i=0;i<sel.options.length;i++){
    var v=parseInt(sel.options[i].value);
    sel.options[i].disabled=(p==='MYP'&&v>10)||(p==='DP'&&v<11);
    sel.options[i].style.display=sel.options[i].disabled?'none':'';
  }
  sel.value=p==='MYP'?'9':'11';
}

function renderSubjects(){
  var grid=document.getElementById('subj-grid');
  grid.innerHTML=DATA[state.prog].map(function(s,i){
    return '<div class="sc" id="sc-'+i+'" onclick="selectSubj('+i+')">'
      +'<div class="sc-icon">'+s.icon+'</div><div class="sc-name">'+s.name+'</div><div class="sc-sub">'+s.sub+'</div></div>';
  }).join('');
}

function selectSubj(i){
  state.subj=i;state.topic=null;state.frameworks=[];
  document.querySelectorAll('.sc').forEach(function(el){el.className='sc'});
  document.getElementById('sc-'+i).className='sc '+(state.prog==='MYP'?'s-myp':'s-dp');
  var topics=DATA[state.prog][i].topics;
  var sel=document.getElementById('topic-select');
  sel.innerHTML='<option value="">— choose a topic —</option>';
  topics.forEach(function(t,ti){var o=document.createElement('option');o.value=ti;o.textContent=t.label;sel.appendChild(o);});
  document.getElementById('topic-explain').style.display='none';
  show('topic-section');hide('enhancer-section');hide('custom-section');hide('out-section');
  smoothScroll('topic-section');
}

function onTopicChange(){
  var val=document.getElementById('topic-select').value;
  if(val===''){hide('topic-explain');hide('enhancer-section');hide('custom-section');return;}
  state.topic=parseInt(val);
  var t=DATA[state.prog][state.subj].topics[state.topic];
  var box=document.getElementById('topic-explain');
  box.className='explain-box '+(state.prog==='MYP'?'ex-br':'ex-sky')+' fade-in';
  box.innerHTML='<strong>What this simulation does:</strong> '+t.explain
    +'<br><br><strong>Key concept:</strong> '+t.concept+' &nbsp;·&nbsp; <strong>Related:</strong> '+t.related
    +'<br><strong>ATL skills:</strong> '+t.atl+' &nbsp;·&nbsp; <strong>Learner profile:</strong> '+t.lp;
  box.style.display='block';
  state.frameworks=[];
  document.querySelectorAll('.fw-card').forEach(function(c){c.classList.remove('fw-on')});
  updateFWCount();
  show('enhancer-section');show('custom-section');
  smoothScroll('enhancer-section');
}

function toggleFW(card){
  var fw=card.getAttribute('data-fw');
  var idx=state.frameworks.indexOf(fw);
  if(idx===-1){state.frameworks.push(fw);card.classList.add('fw-on');}
  else{state.frameworks.splice(idx,1);card.classList.remove('fw-on');}
  updateFWCount();
}

function updateFWCount(){
  var el=document.getElementById('fw-count');
  var n=state.frameworks.length;
  if(n===0){el.textContent='0 frameworks selected — simulation will use default structure';el.className='sel-count none';}
  else{el.textContent=n+' framework'+(n>1?'s':'')+' selected: '+state.frameworks.map(function(f){return FRAMEWORKS[f].name}).join(' · ');el.className='sel-count';}
}

function setupChips(){
  document.querySelectorAll('#style-chips .chip').forEach(function(c){
    c.addEventListener('click',function(){
      document.querySelectorAll('#style-chips .chip').forEach(function(x){x.className='chip'});
      this.className='chip on';state.style=this.dataset.val;
    });
  });
  document.querySelectorAll('#scaffold-chips .chip,#feature-chips .chip').forEach(function(c){
    c.addEventListener('click',function(){
      var on=this.classList.contains('on')||this.classList.contains('on-sky');
      this.classList.remove('on');this.classList.remove('on-sky');
      if(!on)this.classList.add(state.prog==='DP'?'on-sky':'on');
    });
  });
}

function getChipVals(id){
  return Array.from(document.querySelectorAll('#'+id+' .chip.on,#'+id+' .chip.on-sky')).map(function(c){return c.dataset.val});
}

function initCodeBoxes(){
  var wrap=document.getElementById('code-boxes');
  if(!wrap||wrap.children.length>0)return;
  for(var i=0;i<6;i++){
    var inp=document.createElement('input');
    inp.type='text';inp.maxLength=1;inp.className='code-box';
    inp.dataset.idx=i;
    inp.addEventListener('input',function(e){
      var v=e.target.value.replace(/[^A-Za-z0-9!@#$%&*]/g,'');
      e.target.value=v;
      if(v&&parseInt(e.target.dataset.idx)<7){
        var next=wrap.children[parseInt(e.target.dataset.idx)+1];
        if(next)next.focus();
      }
    });
    inp.addEventListener('keydown',function(e){
      if(e.key==='Backspace'&&!e.target.value&&parseInt(e.target.dataset.idx)>0){
        var prev=wrap.children[parseInt(e.target.dataset.idx)-1];
        if(prev){prev.focus();prev.value='';}
      }
    });
    inp.addEventListener('paste',function(e){
      e.preventDefault();
      var pasted=(e.clipboardData||window.clipboardData).getData('text').replace(/[^A-Za-z0-9!@#$%&*]/g,'').slice(0,8);
      var boxes=wrap.children;
      for(var j=0;j<boxes.length;j++) boxes[j].value=pasted[j]||'';
    });
    wrap.appendChild(inp);
  }
}

function setAccessCode(){
  var boxes=document.getElementById('code-boxes').children;
  var code='';
  for(var i=0;i<boxes.length;i++) code+=boxes[i].value;
  code=code.trim();
  if(code.length<1){alert('Please enter at least 1 character for your access code.');return;}
  state.accessCode=code;
  document.getElementById('code-set-display').textContent=code;
  document.getElementById('code-info-display').textContent=code;
  document.getElementById('code-set-confirm').style.display='block';
  document.getElementById('code-set-info').style.display='block';
}

function setAssessment(val){
  state.assessment=val;
  document.getElementById('assess-btn-yes').classList.toggle('a-assess',val===true);
  document.getElementById('assess-btn-yes').classList.toggle('prog-btn',true);
  document.getElementById('assess-btn-no').classList.toggle('a-myp',val===false);
  document.getElementById('assess-btn-no').classList.toggle('prog-btn',true);
  document.getElementById('access-code-wrap').style.display=val?'block':'none';
  if(!val){
    state.accessCode='';
    var boxes=document.getElementById('code-boxes').children;
    for(var i=0;i<boxes.length;i++) boxes[i].value='';
    document.getElementById('code-set-confirm').style.display='none';
    document.getElementById('code-set-info').style.display='none';
  }
  if(val) initCodeBoxes();
}

function buildPrompt(){
  if(state.subj===null||state.topic===null){alert('Please select a subject and topic first.');return;}
  if(state.assessment){
    if(!state.accessCode||state.accessCode.length<1){alert('Please set your assessment access code first — click SET CODE after entering it.');return;}
  }
  var prog=state.prog,subj=DATA[prog][state.subj],t=subj.topics[state.topic];
  var grade=document.getElementById('f-grade').value;
  var rounds=document.getElementById('f-rounds').value;
  var ctx=document.getElementById('f-context').value.trim();
  var scaff=getChipVals('scaffold-chips');var feat=getChipVals('feature-chips');
  var scaffStr=scaff.length?scaff.map(function(s){return '• '+s}).join('\n'):'• Include guiding questions and predict-before-reveal mechanic.';
  var featStr=feat.length?feat.map(function(f){return '• '+f}).join('\n'):'• Animated SVG scene, resource bars, trend chart.';
  var gradeLabel=parseInt(grade)>=11?'Year '+grade:'Grade '+grade;

  // Build framework blocks
  var fwBlocks='';
  if(state.frameworks.length>0){
    fwBlocks='\n\n// \n'
      +'// PROMPT ENHANCEMENT FRAMEWORKS\n'
      +'// \n\n';
    state.frameworks.forEach(function(fw){
      var def=FRAMEWORKS[fw];
      if(fw==='PERSONA') fwBlocks+=def.promptBlock(t,subj.name)+'\n\n';
      else fwBlocks+=def.promptBlock(t)+'\n\n';
    });
  }

  var p='You are an IB '+prog+' '+subj.name+' teacher creating an interactive classroom simulation for '+gradeLabel+' students.\n\n'
    +'// \n'
    +'// SVG CLASSROOM SIMULATION — COMPLETE SPECIFICATION\n'
    +'// \n\n'
    +'SIMULATION TOPIC: '+t.label+'\n\n'
    +'CURRICULUM FRAMEWORK: IB '+prog+' '+subj.name+'\n\n'
    +'KEY CONCEPT: '+t.concept+'\n\n'
    +'RELATED CONCEPT(S): '+t.related+'\n\n'
    +'IB LEARNER PROFILE: '+t.lp+'\n\n'
    +'ATL SKILLS FOCUS: '+t.atl+'\n\n'
    +'LEARNING GOALS:\n'
    +'• Adjust variables and observe cause-and-effect relationships in real time\n'
    +'• Make and test predictions before each round reveals results\n'
    +'• Identify which variables have the most significant impact on outcomes\n'
    +'• Connect outcomes to real-world examples and IB key concepts\n'
    +'• Discuss the ethical dimensions of the decisions made\n'
    +fwBlocks
    +'\nSETTING / VISUAL SCENE:\n'+t.scene+'\n\n'
    +'STUDENT-CONTROLLED VARIABLES (sliders, range 0–4):\n'
    +t.sliders.map(function(s,i){return (i+1)+'. '+s}).join('\n')+'\n\n'
    +'TRACKED RESOURCES / METRICS (animated bars, 0–100):\n'
    +t.resources.join(', ')+'\n\n'
    +'SIMULATION STRUCTURE:\n'
    +rounds+' rounds / phases. Each round: student sets sliders → locks in prediction → clicks Advance → sees outcome.\n\n'
    +'PREDICTION MECHANIC:\n'
    +'Students MUST select a prediction BEFORE Advance activates:\n'
    +'🌱 Thriving | ⚖️ Stable | ⚠️ Resources Stressed | 🔴 Crisis\n'
    +'After revealing, show cause→effect chain (A→B→C) explaining WHY.\n\n'
    +'RANDOM EVENTS:\n'
    +'Include 2–3 unexpected event cards. Events should reward resilient early decisions and penalise over-optimised metrics.\n\n'
    +'REAL-WORLD CONNECTIONS:\n'+t.real+'\n'
    +'Show as "Real-world echo" callout boxes — one per round.\n\n'
    +'IB REFLECTION QUESTIONS (display in final reflection panel):\n'
    +'1. What does "'+t.concept.toLowerCase()+'" mean in this simulation context? Give a real-world example.\n'
    +'2. Which single decision had the most unexpected consequence — and why were you surprised?\n'
    +'3. How would someone from a different cultural or economic background approach these decisions differently?\n'
    +'4. What would you change if you ran the simulation again? Use specific evidence from your results.\n'
    +'5. How does this simulation connect to a current global issue you know about outside school?\n'
    +'6. Which LP attribute did your decision-making best reflect: '+t.lp+'? Justify your choice.\n\n'
    +'VISUAL STYLE:\n'+state.style+'\n\n'
    +'SCAFFOLDING REQUIREMENTS:\n'+scaffStr+'\n\n'
    +'DELIVER AS — a single self-contained HTML file with ALL of the following:\n'+featStr+'\n'
    +'• Phase timeline at top showing all '+rounds+' rounds with active/complete/upcoming states\n'
    +'• Canvas line chart tracking ALL resource metrics across all rounds\n'
    +'• Prediction widget — Advance button DISABLED until prediction selected\n'
    +'• Results modal: outcome grid (▲▼ arrows) + cause-effect chain + IB thinking prompt + real-world echo callout\n'
    +'• Advisor character chip row with hover/tap tooltips giving IB-aligned hints\n'
    +'• IB Reflection panel with all 6 discussion questions\n'
    +'• Toast notification system for key interactions\n'
    +'• Splash screen with: simulation name, '+prog+' curriculum info, '+gradeLabel+', and animated Start button\n'
    +'• Reset button that restores all resources and sliders to starting values\n'
    +'• Works offline — no external dependencies except Google Fonts\n'
    +'• Responsive layout — optimised for classroom projector (1280×720) and student tablet\n'
    +'• Resource bars: green (#16a34a) >60, amber (#d97706) 30–60, red (#dc2626) <30\n'
    +'• Characters react visually: smile when morale/wellbeing metric >60, worried below 40\n'
    +'• Warning icons blink next to any resource bar below 20\n'
    +'• CRITICAL: Every slider change and every round transition MUST produce a clearly visible visual change in the SVG scene — animated, colour-shifted, or structurally different. No round should look the same as the previous one regardless of slider values.'
    +(ctx?'\n\nADDITIONAL CONTEXT FROM TEACHER:\n'+ctx:'')
    +(state.assessment?'\n\nACCESS GATE REQUIREMENT:\nThis simulation is an assessment. Before the splash screen appears, show a full-screen access gate.\n'
      +'ACCESS CODE: '+state.accessCode+'\n'
      +'GATE BEHAVIOUR:\n'
      +'• Show a centred card on a dark overlay as the very first screen on load — all simulation content is hidden behind it.\n'
      +'• Display one input box per character (up to 8 boxes matching the code length) side by side. Auto-advance focus to the next box on each keypress. Support paste-to-fill.\n'
      +'• Input is case-insensitive — compare without case sensitivity. Strip spaces before validating.\n'
      +'• On correct code: gate fades out smoothly, simulation splash screen animates in.\n'
      +'• On wrong code: all boxes shake red, show "Incorrect code — please try again" message, clear all boxes and return focus to box 1.\n'
      +'• Lock the gate for 10 seconds after 3 consecutive failed attempts — show a countdown timer.\n'
      +'• Store the code as a JS constant — it cannot be bypassed by inspecting the URL or skipping JS.\n'
      +'• Visual style of the gate should match the rest of the simulation.\n':'')
    +'\n\n'
    +'\n'
    +'// AFTER GENERATING — AUTOMATICALLY ASK THE TEACHER:\n'
    +'\n\n'
    +'After generating the complete HTML simulation, immediately ask:\n\n'
    +'"✅ Your '+t.label+' simulation for '+prog+' '+gradeLabel+' is ready!'
    +(state.frameworks.length>0?' ('+state.frameworks.map(function(f){return FRAMEWORKS[f].name}).join(' + ')+' frameworks applied)':'')+'\n\n'
    +'Would you like me to enhance it? Choose any:\n\n'
    +'A) 📚 Simplified version — 3 sliders, larger fonts, simpler language (EAL/lower grades)\n'
    +'B) 🎓 HL/Extension questions — higher-order challenge question (with mark allocation) each round\n'
    +'C) 🎨 Retheme — change visual style, colour palette, or character design\n'
    +'D) 👩‍🏫 Teacher panel — hidden panel (T key) with facilitation notes, misconceptions, marking criteria\n'
    +'E) 📝 Student worksheet — printable companion with prediction tables, cause-effect boxes, reflection frames\n'
    +'F) 🌐 Bilingual mode — language toggle (English + Hindi / French / Spanish / Arabic)\n'
    +'G) 🔗 Submission system — student name entry + decision log as downloadable CSV for teacher review\n'
    +'H) 🧠 Add/change prompt framework — apply RTF, SPARK, CREATE, GRADE, Persona, CoT, ToT, ReAct, or Self-Consistency\n\n'
    +'Reply with letter(s) e.g. \'A and D\', or \'none\' to use as-is."';

  document.getElementById('out-body').textContent=p;
  document.getElementById('out-subtitle').textContent=prog+' · '+subj.name+' · '+t.label;
  var badge=document.getElementById('out-badge');
  badge.textContent=prog;badge.className='badge '+(prog==='MYP'?'b-myp':'b-dp');

  // Show applied frameworks bar
  var bar=document.getElementById('fw-applied-bar');
  if(state.frameworks.length>0){
    bar.style.display='flex';
    bar.innerHTML='✦ Frameworks applied: '+state.frameworks.map(function(fw){
      return '<span class="fw-applied-chip">'+FRAMEWORKS[fw].name+'</span>';
    }).join('');
  } else {bar.style.display='none';}

  show('out-section');smoothScroll('out-section');
}

async function openInClaude() {
  var promptText = document.getElementById('out-body').textContent;
  if (!promptText) { alert('Generate a prompt first.'); return; }

  const SAFE_URL_LENGTH = 6000;
  const encoded = encodeURIComponent(promptText);
  const urlWithPrompt = 'https://claude.ai/new?q=' + encoded;

  if (urlWithPrompt.length <= SAFE_URL_LENGTH) {
    // Short enough — prefill via URL
    window.open(urlWithPrompt, '_blank', 'noopener,noreferrer');
    return;
  }

  // Too long — copy to clipboard, open Claude blank, tell the user
  try {
    await navigator.clipboard.writeText(promptText);
    window.open('https://claude.ai/new', '_blank', 'noopener,noreferrer');
    showToast('Prompt copied — paste it into Claude (Ctrl / Cmd + V)');
  } catch (err) {
    // Clipboard API blocked (non-HTTPS or permissions denied) — show manual copy modal
    showManualCopyModal(promptText);
  }
}

function showManualCopyModal(text) {
  // Remove any existing modal
  var existing = document.getElementById('manual-copy-modal');
  if (existing) existing.remove();

  var overlay = document.createElement('div');
  overlay.id = 'manual-copy-modal';
  Object.assign(overlay.style, {
    position: 'fixed', inset: '0', background: 'rgba(10,37,64,0.7)',
    zIndex: '9999', display: 'flex', alignItems: 'center', justifyContent: 'center',
    padding: '1rem'
  });

  overlay.innerHTML =
    '<div style="background:#fff;border-radius:16px;padding:2rem;max-width:560px;width:100%;'
    + 'box-shadow:0 20px 60px rgba(10,37,64,0.3);font-family:Nunito,sans-serif">'
    + '<div style="font-family:\'Playfair Display\',serif;font-size:1.3rem;font-weight:700;'
    + 'color:#0A2540;margin-bottom:8px">Copy your prompt</div>'
    + '<p style="font-size:14px;color:#4A4A4A;margin-bottom:12px;line-height:1.6">'
    + 'Select all and copy the text below, then paste it into Claude.</p>'
    + '<textarea id="mcm-text" readonly style="width:100%;height:180px;font-family:\'DM Mono\',monospace;'
    + 'font-size:12px;padding:10px;border:1.5px solid #DDD8CE;border-radius:8px;resize:none;'
    + 'background:#F5F2EC;color:#2C2C2C;line-height:1.7">' + text.replace(/</g,'&lt;') + '</textarea>'
    + '<div style="display:flex;gap:8px;margin-top:14px;flex-wrap:wrap">'
    + '<button onclick="var t=document.getElementById(\'mcm-text\');t.select();document.execCommand(\'copy\');'
    + 'this.textContent=\'Copied!\';setTimeout(function(){this.textContent=\'Select all & copy\'},2000,this)" '
    + 'style="padding:10px 22px;background:#0A2540;color:#fff;border:none;border-radius:100px;'
    + 'font-family:Nunito,sans-serif;font-size:14px;font-weight:700;cursor:pointer">Select all &amp; copy</button>'
    + '<a href="https://claude.ai/new" target="_blank" rel="noopener noreferrer" '
    + 'style="padding:10px 22px;background:#C9A961;color:#fff;border-radius:100px;'
    + 'font-family:Nunito,sans-serif;font-size:14px;font-weight:700;text-decoration:none;display:inline-flex;align-items:center">'
    + 'Open Claude ↗</a>'
    + '<button onclick="document.getElementById(\'manual-copy-modal\').remove()" '
    + 'style="padding:10px 22px;background:transparent;color:#7A7A7A;border:1.5px solid #DDD8CE;'
    + 'border-radius:100px;font-family:Nunito,sans-serif;font-size:14px;font-weight:700;cursor:pointer">Close</button>'
    + '</div></div>';

  // Close on backdrop click
  overlay.addEventListener('click', function(e) {
    if (e.target === overlay) overlay.remove();
  });

  document.body.appendChild(overlay);
  // Auto-select the text
  setTimeout(function() {
    var ta = document.getElementById('mcm-text');
    if (ta) ta.select();
  }, 80);
}

function copyPrompt(){
  var p=document.getElementById('out-body').textContent;
  if(!p){alert('Generate a prompt first.');return;}
  var btn=document.getElementById('btn-copy');var orig=btn.textContent;
  function done(){btn.textContent='Copied!';setTimeout(function(){btn.textContent=orig},2200)}
  function fallback(){
    var ta=document.createElement('textarea');ta.value=p;ta.style.cssText='position:fixed;top:0;left:0;opacity:0';
    document.body.appendChild(ta);ta.focus();ta.select();
    try{document.execCommand('copy');done()}catch(e){btn.textContent='Select manually'}
    document.body.removeChild(ta);setTimeout(function(){btn.textContent=orig},2200);
  }
  if(navigator.clipboard&&navigator.clipboard.writeText){navigator.clipboard.writeText(p).then(done).catch(fallback)}else{fallback()}
}

function downloadPrompt(){
  var p=document.getElementById('out-body').textContent;
  if(!p){alert('Generate a prompt first.');return;}
  var subj=DATA[state.prog][state.subj];var t=subj.topics[state.topic];
  var fwSuffix=state.frameworks.length?'_'+state.frameworks.join('-'):'';
  var fname='Fountainhead_'+state.prog+'_'+subj.name.replace(/\s+/g,'_')+'_'+t.label.replace(/\W+/g,'_').substring(0,25)+fwSuffix+'_prompt.txt';
  var blob=new Blob([p],{type:'text/plain;charset=utf-8'});
  var url=URL.createObjectURL(blob);var a=document.createElement('a');
  a.href=url;a.download=fname;document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(url);
}

function resetAll(){
  state.subj=null;state.topic=null;state.frameworks=[];state.assessment=false;state.accessCode='';
  hide('topic-section');hide('enhancer-section');hide('custom-section');hide('out-section');
  document.getElementById('assess-btn-yes').classList.remove('a-assess');
  document.getElementById('assess-btn-no').classList.remove('a-myp');
  document.getElementById('access-code-wrap').style.display='none';
  var boxes=document.getElementById('code-boxes').children;
  for(var i=0;i<boxes.length;i++) boxes[i].value='';
  document.getElementById('code-set-confirm').style.display='none';
  document.getElementById('code-set-info').style.display='none';
  document.querySelectorAll('.sc').forEach(function(el){el.className='sc'});
  document.getElementById('topic-select').value='';
  document.querySelectorAll('.fw-card').forEach(function(c){c.classList.remove('fw-on')});
  updateFWCount();
  window.scrollTo({top:0,behavior:'smooth'});
}

async function sendMod(msg){
  var full='Here is the simulation I asked you to build:\n\n[PASTE OR REGENERATE THE SIMULATION]\n\nNow please make the following change:\n\n'+msg;
  const SAFE_URL_LENGTH = 6000;
  const encoded = encodeURIComponent(full);
  const urlWithPrompt = 'https://claude.ai/new?q=' + encoded;
  if (urlWithPrompt.length <= SAFE_URL_LENGTH) {
    window.open(urlWithPrompt, '_blank', 'noopener,noreferrer');
    return;
  }
  try {
    await navigator.clipboard.writeText(full);
    window.open('https://claude.ai/new', '_blank', 'noopener,noreferrer');
    showToast('Modification copied — paste into Claude (Ctrl / Cmd + V)');
  } catch(err) {
    showManualCopyModal(full);
  }
}

function openCustomMod(){
  var a=document.getElementById('custom-mod-area');
  a.style.display=a.style.display==='none'?'block':'none';
}
function sendCustomMod(){var txt=document.getElementById('custom-mod-txt').value.trim();if(txt)sendMod(txt);}

function copyGuidePrompt(btn){
  var text=document.getElementById('master-prompt-blk').innerText||'';var orig=btn.textContent;
  function done(){btn.textContent='Copied!';btn.classList.add('done');setTimeout(function(){btn.textContent=orig;btn.classList.remove('done')},2200)}
  function fallback(){var ta=document.createElement('textarea');ta.value=text;ta.style.cssText='position:fixed;top:0;left:0;opacity:0';document.body.appendChild(ta);ta.focus();ta.select();try{document.execCommand('copy');done()}catch(e){btn.textContent='Manual copy';}document.body.removeChild(ta);}
  if(navigator.clipboard&&navigator.clipboard.writeText){navigator.clipboard.writeText(text).then(done).catch(fallback)}else{fallback()}
}

function show(id){var el=document.getElementById(id);if(el){el.style.display='block';el.classList.add('fade-in')}}
function hide(id){var el=document.getElementById(id);if(el)el.style.display='none'}
function smoothScroll(id){var el=document.getElementById(id);if(el)setTimeout(function(){el.scrollIntoView({behavior:'smooth',block:'start'})},80)}

